        if (client['Услуга: Мойка']) services.push('🚿 Мойка');
        if (client['Услуга: Упаковка']) services.push('🧧 Упаковка');
        const servicesLine = services.length > 0 ? `\n<b>Доп. услуги:</b> ${services.join(', ')}` : '';

