📑 <b>Договор:</b> ${client['Договор']}

<i>Приём и хранение осуществляется на условиях публичной оферты otelshin.ru/dogovor</i>
`.trim().replace(/^\s+/gm, '');
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

