                ];
                const uniqueIds = [...new Set(allRecipientIds)];

                if (uniqueIds.length > 0) {
                    const message = formatManagerMessage(finalClientData);
                    Promise.all(uniqueIds.map(id => api.sendMessage(id, message))).catch(console.error);
                }
